// Rohe PDF-Bytes aus dem Webhook-Body in Base64 konvertieren
const item = $input.first();

// n8n speichert binary POST-Daten in item.binary.data
if (item.binary?.data) {
  return [{ json: { pdfBase64: item.binary.data.data } }];
}

// Fallback: body als Buffer/String
const body = item.json?.body;
if (!body) throw new Error('Keine PDF-Daten empfangen');

let buffer;
if (Buffer.isBuffer(body)) {
  buffer = body;
} else if (typeof body === 'string') {
  buffer = Buffer.from(body, 'binary');
} else {
  buffer = Buffer.from(body);
}

return [{ json: { pdfBase64: buffer.toString('base64') } }];

// PDF als inline_data direkt an Gemini schicken – funktioniert auch bei Scans
const pdfBase64 = $input.first().json.pdfBase64;

if (!pdfBase64) throw new Error('Keine PDF-Daten vorhanden');

const prompt = `Analysiere diese Rechnung und extrahiere alle relevanten Daten als JSON.\n\nExtrahiere genau diese Felder:\n- rechnungs_nummer: Rechnungsnummer (String)\n- lieferant: Name des Lieferanten (String)\n- betrag: Gesamtbetrag als Zahl ohne Waehrungssymbol (Number)\n- waehrung: Waehrungscode EUR, USD, CHF oder GBP (String)\n- datum: Rechnungsdatum im Format YYYY-MM-DD (String)\n- eingangskanal: "Email" wenn nicht anders angegeben (String)\n- rechnungspositionen: Array mit Positionen, jede mit: beschreibung (String), menge (Number), einheit (String, z.B. Stk.), einzelpreis (Number)\n\nAntworte NUR mit dem JSON-Objekt, ohne Erklaerungstext, ohne Markdown-Code-Bloecke.`;

const requestBody = JSON.stringify({
  contents: [{
    parts: [
      {
        inline_data: {
          mime_type: 'application/pdf',
          data: pdfBase64
        }
      },
      {
        text: prompt
      }
    ]
  }]
});

return [{ json: { requestBody } }];

// Gemini-Antwort parsen
const response = $input.first().json;
const rawText = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';

let jsonText = rawText.trim();
if (jsonText.startsWith('```')) {
  jsonText = jsonText.replace(/^```json?\n?/, '').replace(/\n?```$/, '');
}

let extracted;
try {
  extracted = JSON.parse(jsonText);
} catch (e) {
  throw new Error(`JSON-Parsing fehlgeschlagen: ${e.message}\nAntwort: ${rawText.substring(0, 300)}`);
}

const result = {
  rechnungs_nummer: String(extracted.rechnungs_nummer || 'UNBEKANNT'),
  lieferant: String(extracted.lieferant || 'UNBEKANNT'),
  betrag: parseFloat(extracted.betrag) || 0,
  waehrung: ['EUR','USD','CHF','GBP'].includes(extracted.waehrung) ? extracted.waehrung : 'EUR',
  datum: extracted.datum || new Date().toISOString().split('T')[0],
  eingangskanal: extracted.eingangskanal || 'Email',
  rechnungspositionen: Array.isArray(extracted.rechnungspositionen) ? extracted.rechnungspositionen : [],
  ki_extraktion_erfolgreich: true,
  ki_extraktion_zeitstempel: new Date().toISOString(),
};

return [{ json: result }];
